def word_lengths(word_list):
    """
    Maps a list of words to a dictionary where keys are words and values are their lengths.
    """
    result = {}
    for word in word_list:
        result[word] = len(word)
    return result

def count_non_empty_lines(filename):
    count = 0
    try:
        with open(filename, 'r') as file:
            for line in file:
                if line.strip():
                    count += 1
        return count
    except FileNotFoundError:
        return -1
